func (o *Track) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Events":
		rels, ok := retrieved.(EventSlice)
		if !ok {
			return fmt.Errorf("track cannot load %T as %q", retrieved, name)
		}

		o.R.Events = rels
		o.R.Loaded.Events = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.Track = o
				rel.R.Loaded.Track = true
			}
		}
		return nil
	default:
		return fmt.Errorf("track has no relationship %q", name)
	}
}

type trackPreloader struct{}

func buildTrackPreloader() trackPreloader {
	return trackPreloader{}
}

type trackThenLoader[Q orm.Loadable] struct {
	Events func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildTrackThenLoader[Q orm.Loadable]() trackThenLoader[Q] {
	type EventsLoadInterface interface {
		LoadEvents(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return trackThenLoader[Q]{
		Events: thenLoadBuilder[Q](
			"Events",
			func(ctx context.Context, exec bob.Executor, retrieved EventsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadEvents(ctx, exec, mods...)
			},
		),
	}
}

// LoadEvents loads the track's Events into the .R struct
func (o *Track) LoadEvents(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Events = nil
	o.R.Loaded.Events = false

	related, err := o.Events(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Track = o
		rel.R.Loaded.Track = true
	}

	o.R.Events = related
	o.R.Loaded.Events = true
	return nil
}

// LoadEvents loads the track's Events into the .R struct
func (os TrackSlice) LoadEvents(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	events, err := os.Events(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Events = nil
		o.R.Loaded.Events = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	trackByKey := make(map[int32][]*Track, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		trackByKey[o.ID] = append(trackByKey[o.ID], o)
	}

	for _, rel := range events {

		owners, ok := trackByKey[rel.TrackID]
		if !ok {
			continue
		}

		for _, o := range owners {

			rel.R.Track = o
			rel.R.Loaded.Track = true

			o.R.Events = append(o.R.Events, rel)

		}
	}

	return nil
}

// trackC is where relationship counts are stored.
type trackC struct {
	Events *int64
}

// PreloadCount sets a count in the C struct by name
func (o *Track) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Events":
		o.C.Events = &count
	}
	return nil
}

type trackCountPreloader struct {
	Events func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
}

func buildTrackCountPreloader() trackCountPreloader {
	return trackCountPreloader{
		Events: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*Track]("Events", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = Tracks.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(Events.NameAsExpr()),
					sm.Where(psql.Quote(Events.Alias(), "track_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
	}
}

type trackCountThenLoader[Q orm.Loadable] struct {
	Events func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildTrackCountThenLoader[Q orm.Loadable]() trackCountThenLoader[Q] {
	type EventsCountInterface interface {
		LoadCountEvents(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return trackCountThenLoader[Q]{
		Events: countThenLoadBuilder[Q](
			"Events",
			func(ctx context.Context, exec bob.Executor, retrieved EventsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountEvents(ctx, exec, mods...)
			},
		),
	}
}

// LoadCountEvents loads the count of Events into the C struct
func (o *Track) LoadCountEvents(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	count, err := o.Events(mods...).Count(ctx, exec)
	if err != nil {
		return err
	}

	o.C.Events = &count
	return nil
}

// LoadCountEvents loads the count of Events for a slice in a single batch query
func (os TrackSlice) LoadCountEvents(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs

	pkID := make(pgtypes.Array[int32], 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		pkID = append(pkID, o.ID)
	}
	PKArgExpr := psql.Select(sm.Columns(
		psql.F("unnest", psql.Cast(psql.Arg(pkID), "integer[]")),
	))

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    int32
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			Events.Columns.TrackID.As("id"),
			psql.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(Events.NameAsExpr()),

		// WHERE fk IN (parent PKs)
		sm.Where(Events.Columns.TrackID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(Events.Columns.TrackID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		psql.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[int32]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.Events = &count
	}

	return nil
}

type trackJoins[Q dialect.Joinable] struct {
	typ    string
	Events modAs[Q, eventColumns]
}

func (j trackJoins[Q]) aliasedAs(alias string) trackJoins[Q] {
	return buildTrackJoins[Q](buildTrackColumns(alias), j.typ)
}

func buildTrackJoins[Q dialect.Joinable](cols trackColumns, typ string) trackJoins[Q] {
	return trackJoins[Q]{
		typ: typ,
		Events: modAs[Q, eventColumns]{
			c: Events.Columns,
			f: func(to eventColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Events.NameExpr().As(to.Alias())).On(
						to.TrackID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
